member.example:
Bind the TMP_Dropdown alphaFadeSpeed property using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownAlphaFadeSpeedBinder _alphaFadeSpeed;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alphaFadeSpeed;
    }


Bind the TMP_Dropdown alphaFadeSpeed property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Dropdown _dropdown;
        
        private DropdownAlphaFadeSpeedBinder AlphaFadeSpeed =>
            new(_dropdown);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alphaFadeSpeed;
    }

Switch the TMP_Dropdown alphaFadeSpeed between two values using a serialized binder field — the target TMP_Dropdown is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DropdownAlphaFadeSpeedSwitcherBinder _isFastFade;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isFastFade;
    }


Switch the TMP_Dropdown alphaFadeSpeed between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TMP_Dropdown _dropdown;
        
        [SerializeField]
        private float _fastFadeSpeed;
        
        [SerializeField]
        private float _slowFadeSpeed;
        
        private DropdownAlphaFadeSpeedSwitcherBinder IsFastFade => new(
            _dropdown, _fastFadeSpeed, _slowFadeSpeed, null);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isFastFade;
    }
